def binary_search(arr, target):
    left = 0
    right = len(arr) -1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid+1
        else:
            right = mid-1
    return -1

def gcd(a, b):
    while b != 0:
        a, b = b, a % b
    return abs(a)

def matrix_multiply(A, B):
    result = [[0 for x in range(len(B[0]))] for y in range(len(A))]
    for i in range (len(A)):
        for j in range (len(B[0])):
            for k in range (len(B)):
                result[i][j] += A[i][k]*B[k][j]
     return result
